// Helper: get candidates for a specific club and position
export const getCandidatesByClubAndPosition = (clubId, position) => {
  return CANDIDATES.filter(
    (c) => c.club_id === clubId && c.position === position
  );
};

// Helper: get all candidates for a specific club
export const getCandidatesByClub = (clubId) => {
  return CANDIDATES.filter((c) => c.club_id === clubId);
};
